    });

    it('trims the query before navigating', async () => {
      const { searchInput, searchBtn } = setup({ hash: toBrowseHash('docs') });
      await flush();

      searchInput.value = '   spaced   ';
      searchBtn.click();

      expect(window.location.hash).toBe(toSearchHash('spaced', 'docs'));
    });

    it('clears the search (returns to browse) when the query is empty', async () => {
      const { searchInput, searchBtn } = setup({ hash: toSearchHash('foo', 'docs') });
      await flush();

      searchInput.value = '';
      searchBtn.click();

      expect(window.location.hash).toBe(toBrowseHash('docs'));
    });

    it('clears the search when the query is only whitespace', async () => {
      const { searchInput, searchBtn } = setup({ hash: toSearchHash('foo', 'docs') });
      await flush();

      searchInput.value = '   \t  ';
      searchBtn.click();

      expect(window.location.hash).toBe(toBrowseHash('docs'));
    });

    it('navigates when Enter is pressed inside the search input', async () => {
      const { searchInput } = setup({ hash: toBrowseHash('docs') });
      await flush();

      searchInput.value = 'foo';
      searchInput.dispatchEvent(new KeyboardEvent('keydown', { key: 'Enter' }));

      expect(window.location.hash).toBe(toSearchHash('foo', 'docs'));
    });
  });

  describe('upload', () => {
    function setFiles(input: HTMLInputElement, names: string[]): void {
      const dt = new DataTransfer();
      for (const n of names) dt.items.add(new File(['data-' + n], n));
      input.files = dt.files as unknown as FileList;
    }

    /** Drain queued microtasks enough times for the upload loop + re-render. */
    const settle = async (n = 10): Promise<void> => {
      for (let i = 0; i < n; i++) await flush();
    };

    /**
     * Build a fetch impl that rejects POST /upload for the named files (via a
     * non-ok Response, exactly how `ApiClient.request` surfaces failures) while
     * still serving normal browse/upload responses for everything else.
     */
    function failingUploadImpl(failingNames: string[]) {
      const failing = new Set(failingNames);
      return async (url: string, init?: RequestInit): Promise<Response> => {
        const u = String(url);
        const method = (init?.method ?? 'GET').toUpperCase();
        if (method === 'POST' && u.includes('/upload')) {
          const file = (init?.body as FormData | undefined)?.get('file') as File | null;
          if (file && failing.has(file.name)) {
            return mockResponse({ ok: false, status: 413, text: 'too large' });
          }
          return mockResponse({ status: 200, body: { path: file?.name ?? '' } });
        }
        if (method === 'GET' && u.includes('/browse')) {
          const raw = u.split('path=')[1] ?? '';
          const path = decodeURIComponent(raw);
          const child = 'child-of-' + (path || 'root');
          return mockResponse({
            body: browseResult({
              path,
              entries: [fileEntry({ name: child, path: joinPathHelper(path, child) })],
              fileCount: 1,
              totalSize: 10,
            }),
          });
        }
        return mockResponse({ status: 200, body: {} });
      };
    }

    /** Ordered names of files POSTed to /upload so far. */
    function uploadedFileNames(): string[] {
      return fetchMock.mock.calls
        .filter(([u, init]) => String(u).includes('/upload') && (init?.method ?? 'GET') === 'POST')
        .map(([, init]) => ((init?.body as FormData | undefined)?.get('file') as File | null)?.name ?? '');
    }

    /** Count of GET /browse calls observed so far. */
    function browseCount(): number {
      return fetchMock.mock.calls.filter(
        ([u, init]) => String(u).includes('/browse') && (init?.method ?? 'GET') === 'GET',
      ).length;
    }

    it('uploads each selected file to the current browse path, then clears the input and re-renders', async () => {
      const { uploadInput } = setup({ hash: toBrowseHash('docs') });
      await flush();

      setFiles(uploadInput, ['a.txt', 'b.txt']);
      uploadInput.dispatchEvent(new Event('change'));
      await flush();
      await flush();

      const uploadCalls = fetchMock.mock.calls.filter(
        ([u, init]) => String(u).includes('/upload') && (init?.method ?? 'GET') === 'POST',
      );
      expect(uploadCalls).toHaveLength(2);
      for (const [, init] of uploadCalls) {
        expect(init?.body).toBeInstanceOf(FormData);
        expect((init!.body as FormData).get('file')).toBeInstanceOf(File);
      }
      // All uploads target the current browse path.
      expect(uploadCalls.every(([u]) => String(u).includes('path=' + encodeURIComponent('docs')))).toBe(true);
      // The input is cleared afterwards.
      expect(uploadInput.value).toBe('');
      // And a re-render occurred (browse fetched again after upload).
      const browseCalls = fetchMock.mock.calls.filter(([u]) => String(u).includes('/browse'));
      expect(browseCalls.length).toBeGreaterThan(0);
    });

    it('uploads nothing when no files are selected', async () => {
      const { uploadInput } = setup({ hash: toBrowseHash('docs') });
      await flush();

      uploadInput.dispatchEvent(new Event('change'));
      await flush();

      expect(
        fetchMock.mock.calls.some(([u]) => String(u).includes('/upload')),
      ).toBe(false);
    });

    // ---- per-file error handling -------------------------------------------
    // A single failing upload must NOT abort the remaining uploads, swallow the
    // re-render, or leave the input uncleared. Each failure is surfaced in the
    // status footer (see task spec: "Uploaded N file(s); failed: a.txt, b.txt").

    it('continues uploading the remaining files when a middle upload fails, then clears the input, re-renders, and surfaces the failure', async () => {
      fetchMock.mockImplementation(failingUploadImpl(['b.txt']));
      const { uploadInput, status } = setup({ hash: toBrowseHash('docs') });
      await flush();
      const browseBefore = browseCount();

      setFiles(uploadInput, ['a.txt', 'b.txt', 'c.txt']);
      uploadInput.dispatchEvent(new Event('change'));
      await settle();

      // All three uploads were attempted — including the failing one — in order.
      expect(uploadedFileNames()).toEqual(['a.txt', 'b.txt', 'c.txt']);
      // The input is cleared even though one upload failed.
      expect(uploadInput.value).toBe('');
      // A re-render still happened after the upload loop.
      expect(browseCount()).toBeGreaterThan(browseBefore);
      // The failure is surfaced in the status footer: it names the failing
      // file and acknowledges the two files that did upload.
      expect(status.textContent).toMatch(/failed/i);
      expect(status.textContent).toContain('b.txt');
      expect(status.textContent).toMatch(/Uploaded\s+2/i);
      // Successful files are not flagged as failed.
      expect(status.textContent).not.toContain('c.txt');
      expect(status.textContent).not.toContain('a.txt');
    });

    it('continues uploading subsequent files when the first upload fails', async () => {
      fetchMock.mockImplementation(failingUploadImpl(['bad.txt']));
      const { uploadInput, status } = setup({ hash: toBrowseHash('docs') });
      await flush();

      setFiles(uploadInput, ['bad.txt', 'good.txt']);
      uploadInput.dispatchEvent(new Event('change'));
      await settle();

      expect(uploadedFileNames()).toEqual(['bad.txt', 'good.txt']);
      expect(uploadInput.value).toBe('');
      expect(status.textContent).toMatch(/failed/i);
      expect(status.textContent).toContain('bad.txt');
      expect(status.textContent).not.toContain('good.txt');
    });

    it('clears the input, re-renders, and lists every failure when all uploads fail', async () => {
      fetchMock.mockImplementation(failingUploadImpl(['x.txt', 'y.txt']));
      const { uploadInput, status } = setup({ hash: toBrowseHash('docs') });
      await flush();
      const browseBefore = browseCount();

      setFiles(uploadInput, ['x.txt', 'y.txt']);
      uploadInput.dispatchEvent(new Event('change'));
      await settle();

      expect(uploadedFileNames()).toEqual(['x.txt', 'y.txt']);
      expect(uploadInput.value).toBe('');

content.text:
      expect(browseCount()).toBeGreaterThan(browseBefore);
      expect(status.textContent).toMatch(/failed/i);
      expect(status.textContent).toContain('x.txt');
      expect(status.textContent).toContain('y.txt');
    });

    it('does not surface a failure message when every upload succeeds (status stays the normal browse summary)', async () => {
      const { uploadInput, status } = setup({ hash: toBrowseHash('docs') });
      await flush();

      setFiles(uploadInput, ['a.txt', 'b.txt']);
      uploadInput.dispatchEvent(new Event('change'));
      await settle();

      expect(uploadInput.value).toBe('');
      // No failure report; renderBrowse's normal "N folders, M files, total S"
      // summary is what the re-render leaves behind.
      expect(status.textContent).not.toMatch(/failed/i);
      expect(status.textContent).toMatch(/folders.*files.*total/);
    });
  });
});

/* ===========================================================================
 * Import characterization (safety net for unused-import removal)
 *
 * `src/app.ts` imports `parseHash` (from ./router.js), `parentPath`, and
 * `basename` (from ./format.js) that are never referenced in the module body
 * and are slated for removal. Removing unused imports cannot change runtime
 * behavior, so these tests guard the OTHER behaviors: they pin the observable
 * outputs that depend on the imports which STAY — especially the ones that
 * share an import line with the removed names, where a careless edit could
 * drop a needed sibling. Each assertion checks a concrete value tied to one
 * retained import's real usage in the app; if that import were removed, the
 * referenced call would throw (ReferenceError) or emit wrong output and the
 * test would fail.
 *
 * Retained imports exercised here:
 *   format.js: joinPath, normalizeRelativePath, formatBytes, formatDate
 *   router.js: toBrowseHash, toSearchHash
 * (getCurrentRoute / subscribe / navigate are already covered by the render
 * orchestration and toolbar-handler suites above.)
 * ========================================================================= */
describe('import characterization (KEEP-list behaviors)', () => {
  // Local leaf finder; the breadcrumb describe has its own scoped copy.
  function leafByText(container: Element, text: string): HTMLElement | undefined {
    return Array.from(container.querySelectorAll('*')).find(
      (el) => el.children.length === 0 && (el.textContent ?? '').trim() === text,
    ) as HTMLElement | undefined;
  }

  /* --- format.js KEEP imports (siblings of the removed parentPath/basename) --- */

  describe('joinPath (breadcrumb cumulative paths)', () => {
    it('joins each cumulative segment across three path levels', async () => {
      const { breadcrumb } = await setupCleared();
      renderBrowse(browseResult({ path: 'a/b/c', entries: [] }), browseRoute('a/b/c'));

      leafByText(breadcrumb, 'c')!.click();
      expect(window.location.hash).toBe(toBrowseHash('a/b/c'));

      leafByText(breadcrumb, 'b')!.click();
      expect(window.location.hash).toBe(toBrowseHash('a/b'));
    });
  });

  describe('normalizeRelativePath (breadcrumb path cleaning)', () => {
    it('collapses leading/doubled/trailing slashes before splitting segments', async () => {
      const { breadcrumb } = await setupCleared();
      renderBrowse(browseResult({ path: '//a//b//' }), browseRoute('//a//b//'));

      leafByText(breadcrumb, 'b')!.click();
      expect(window.location.hash).toBe(toBrowseHash('a/b'));
    });
  });

  describe('formatBytes (size column)', () => {
    it('renders a 0-byte file as "0 B" (sub-KB integer branch)', async () => {
      const entry = fileEntry({ name: 'empty.txt', path: 'docs/empty.txt', size: 0 });
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [entry] }), browseRoute('docs'));

      const sizeCell = cellsOf(rowByName(results.querySelector('table')!, 'empty.txt')!)[1];
      expect(sizeCell.textContent?.trim()).toBe('0 B');
    });
  });

  describe('formatDate (modified column)', () => {
    it('renders an empty Modified cell when lastModified is empty (fallback)', async () => {
      const entry = fileEntry({ name: 'nodate.txt', path: 'docs/nodate.txt', lastModified: '' });
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [entry] }), browseRoute('docs'));

      const modifiedCell = cellsOf(rowByName(results.querySelector('table')!, 'nodate.txt')!)[2];
      expect(modifiedCell.textContent).toBe('');
    });
  });

  /* --- router.js KEEP imports (siblings of the removed parseHash) --- */

  describe('toBrowseHash (per-segment percent-encoding)', () => {
    it('encodes spaces in directory names when navigating into a folder', async () => {
      const dir = fileEntry({ name: 'my folder', path: 'docs/my folder', isDirectory: true });
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [dir] }), browseRoute('docs'));

      clickNameLink(rowByName(results.querySelector('table')!, 'my folder')!);

      expect(window.location.hash).toBe('#/browse/docs/' + encodeURIComponent('my folder'));
      expect(window.location.hash).toBe(toBrowseHash('docs/my folder'));
    });
  });

  describe('toSearchHash (query/path percent-encoding)', () => {
    it('encodes special characters in the search query and scope path', async () => {
      const { searchInput, searchBtn } = setup({ hash: toBrowseHash('docs') });
      await flush();

      searchInput.value = 'a & b=c?';
      searchBtn.click();

      const expected =
        '#/search?q=' + encodeURIComponent('a & b=c?') + '&path=' + encodeURIComponent('docs');
      expect(window.location.hash).toBe(expected);
      expect(window.location.hash).toBe(toSearchHash('a & b=c?', 'docs'));
    });
  });
});

/* ===========================================================================
 * Rendering lifecycle
 *
 * Two interrelated startApp/render bugs are pinned here:
 *
 *  (a) LISTENER LEAK — startApp calls subscribe(render) and used to throw away
 *      the returned unsubscribe function, so every re-mount left the previous
 *      mount's hashchange listener on `window`. (happy-dom dedups identical
 *      function references, so this leak is latent rather than multiplicative
 *      in this environment, but the cleanup contract is still asserted via the
 *      addEventListener/removeEventListener spies below.)
 *  (b) RENDER RACE — render() is async; two rapid navigations let a slower
 *      fetch overwrite a fresher one's results. The fix aborts a superseded
 *      render after each await.
 * ========================================================================= */
describe('rendering lifecycle', () => {
  describe('hashchange listener cleanup on re-mount', () => {
    /**
     * Mount the app `n` times into fresh containers, the way `setup()` does.
     * Returns nothing; used to drive repeated startApp() calls with the spies
     * already installed so every subscribe/unsubscribe is captured.
     */
    function mountNTimes(n: number): void {
      for (let i = 0; i < n; i++) {
        document.body.innerHTML = '';
        window.location.hash = '';
        const root = document.createElement('div');
        document.body.append(root);
        startApp(root);
      }
    }

    function hashchangeCalls(
      spy: ReturnType<typeof vi.spyOn>,
    ): Array<{ type: string; callback: EventListenerOrEventListenerObject }> {
      return spy.mock.calls
        .map(([type, callback]) => ({ type: String(type), callback }))
        .filter((c) => c.type === 'hashchange');
    }

    it('subscribes exactly one hashchange listener per mount', async () => {
      const addSpy = vi.spyOn(window, 'addEventListener');

      mountNTimes(3);
      await flush();

      // Each startApp() subscribes render exactly once.
      expect(hashchangeCalls(addSpy)).toHaveLength(3);
    });

    it('unsubscribes the previous mount\'s hashchange listener on every re-mount', async () => {
      const addSpy = vi.spyOn(window, 'addEventListener');
      const removeSpy = vi.spyOn(window, 'removeEventListener');

      const N = 4;
      mountNTimes(N);
      await flush();

      const adds = hashchangeCalls(addSpy);
      const removes = hashchangeCalls(removeSpy);

      // Robust to test ordering: the 1st mount in *this* test may additionally
      // tear down a listener left over by an earlier test, so we only assert a
      // lower bound. The invariant that matters is that every re-mount removes
      // its predecessor — i.e. at least (N − 1) hashchange removals happened.
      // The leaky implementation performs ZERO removals.
      expect(adds).toHaveLength(N);
      expect(removes.length).toBeGreaterThanOrEqual(N - 1);
      // Every removal targets the same render callback that was subscribed.
      expect(removes.length).toBeGreaterThan(0);
      for (const r of removes) {
        expect(typeof r.callback).toBe('function');
        expect(adds.some((a) => a.callback === r.callback)).toBe(true);
      }
    });
  });

  describe('render race (superseded fetch is discarded)', () => {
    /**
     * Drive a browse render for `path` whose fetch is held open until the
     * caller invokes `release()`. All other browse paths resolve immediately.
     */
    function stubHeldBrowse(
      heldPath: string,
    ): { release: () => void } {
      let release!: () => void;
      const held = new Promise<Response>((resolve) => {
        release = () =>
          resolve(
            mockResponse({
              body: browseResult({
                path: heldPath,
                entries: [
                  fileEntry({
                    name: 'child-of-' + heldPath,
                    path: joinPathHelper(heldPath, 'child-of-' + heldPath),
                  }),
                ],
                fileCount: 1,
                totalSize: 1,
              }),
            }),
          );
      });

      fetchMock.mockImplementation(async (url, init) => {
        const u = String(url);
        const method = (init?.method ?? 'GET').toUpperCase();
        if (method === 'GET' && u.includes('/browse')) {
          const path = decodeURIComponent(u.split('path=')[1] ?? '');
          if (path === heldPath) {
            return held;
          }
          return mockResponse({
            body: browseResult({
              path,
              entries: [
                fileEntry({
                  name: 'child-of-' + path,
                  path: joinPathHelper(path, 'child-of-' + path),
                }),
              ],
              fileCount: 1,
              totalSize: 1,
            }),
          });
        }
        return mockResponse({ status: 200, body: {} });
      });

      return { release };
    }

    it('does not let a slower, superseded browse overwrite the latest results', async () => {
      const { release } = stubHeldBrowse('slow');

      const { results } = setup();
      await flush(); // settle the initial render for the default route

      // Navigate to 'slow' (its fetch is held), then — before it resolves — to
      // 'fast'. In happy-dom each hash assignment fires `hashchange` and thus
      // render() synchronously, so both fetches are issued in order and the
      // 'slow' render is suspended at its await when 'fast' starts.
      navigate(toBrowseHash('slow'));
      navigate(toBrowseHash('fast'));
      await flush(); // 'fast' resolves first and commits

      expect(results.textContent).toContain('child-of-fast');
      expect(results.textContent).not.toContain('child-of-slow');

      // The slow fetch finally resolves LAST. Its stale data must be discarded
      // (a newer render owns the slot) and must NOT clobber the fresh results.
      release();
      await flush();

      expect(results.textContent).toContain('child-of-fast');
      expect(results.textContent).not.toContain('child-of-slow');
    });

    it('does not let a superseded browse update the breadcrumb or status', async () => {
      const { release } = stubHeldBrowse('slow');

      const { breadcrumb, status } = setup();
      await flush();

      navigate(toBrowseHash('slow'));
      navigate(toBrowseHash('fast'));
      await flush();

      // The fresh render owns the breadcrumb / status for 'fast'.
      expect(breadcrumb.textContent).toContain('fast');
      expect(status.textContent).toContain('1 files');

      release();
      await flush();

      // The superseded 'slow' render must not have touched them.
      expect(breadcrumb.textContent).toContain('fast');
      expect(breadcrumb.textContent).not.toContain('slow');
      expect(status.textContent).toContain('1 files');
    });

    it('still renders the latest navigation when fetches resolve in order', async () => {
      // Control case: a single navigation (no race) still commits normally,
      // so the race guard does not swallow a non-superseded render.
      const { results } = setup({ hash: toBrowseHash('solo') });
      await flush();

      expect(results.textContent).toContain('child-of-solo');

      navigate(toBrowseHash('next'));
      await flush();

      expect(results.textContent).toContain('child-of-next');
      expect(results.textContent).not.toContain('child-of-solo');
    });
  });
});

/**
 * SPA entry — wires `api`, `router`, and the DOM into a file-browser UI
 * rendered inside a native `<dialog>` widget.
 *
 * Structure (built imperatively via `document.createElement`):
 *
 *   .file-browser-host   — primary chromeless surface; hosts the widget while
 *                          the dialog is closed (embedded view)
 *   <button class="trigger">Browse Files</button>
 *   <dialog class="browser-dialog">  — frame + titlebar (dialog-only chrome)
 *     .dialog-header     — title <span> + Close icon <button>
 *     .dialog-body        — empty slot; the shared widget moves here on open
 *
 *   The shared .file-browser widget (toolbar + .results + .status) is MOVED
 *   between the embedded host and the dialog body as the dialog opens/closes.
 *   It carries no border/background/title of its own — only the dialog adds
 *   the frame + titlebar, so the embedded view is chromeless.
 *
 *   .file-browser:
 *     toolbar   — .breadcrumb + search <input> + <button> + <label> upload
 *     .results  — file/folder <table>
 *     <footer class="status"> — summary line
 *
 * All user-controlled strings (file/folder names, paths) are inserted via
 * `textContent` / element creation — never via `innerHTML` — to prevent HTML
 * injection.
 */
import { ApiClient } from './api.js';
import type { BrowseResult, FileEntry, SearchResult } from './api.js';
import { getCurrentRoute, subscribe, toBrowseHash, toSearchHash, navigate } from './router.js';
import type { Route } from './router.js';
import { formatBytes, normalizeRelativePath, joinPath, formatDate } from './format.js';

const api = new ApiClient();

/* -------------------------------------------------------------------------
 * Module-level DOM references
 *
 * `startApp` populates these once per mount. `render`, `renderBrowse`, and
 * `renderSearch` (the latter two are exported for direct unit testing) all
 * operate against them, so they always target the most recently mounted app.
 * Tests re-run `startApp` against a fresh container, re-binding these each
 * time.
 * ---------------------------------------------------------------------- */
let resultsEl!: HTMLElement;
let statusEl!: HTMLElement;
let breadcrumbEl!: HTMLElement;
let searchInput!: HTMLInputElement;
let uploadInput!: HTMLInputElement;

/* -------------------------------------------------------------------------
 * Rendering-lifecycle state
 *
 * `unsubscribe` holds the teardown for the CURRENT mount's hashchange listener.
 * `startApp` clears any previous listener before subscribing a new one, so a
 * re-mount never leaves the old listener on `window` (memory leak fix).
 *
 * `renderToken` is a monotonic counter incremented at the start of every
 * `render()`. Each in-flight render captures its token and, after each `await`,
 * bails out if a newer render has started — preventing a slower, superseded
 * fetch from clobbering the freshest results (render-race fix).
 * ---------------------------------------------------------------------- */
let unsubscribe: (() => void) | null = null;
let renderToken = 0;

/* =========================================================================
 * startApp — build the DOM, wire events, kick off rendering
 * ========================================================================= */

export function startApp(root: HTMLElement): void {
  root.innerHTML = '';

  /* --- File-browser widget (chromeless; shared by the embedded view and the
     dialog). It owns the toolbar, results, and status. The frame and titlebar
     belong to whichever host renders it — never to the widget itself — so when
     it is embedded directly in the page it carries no border/background/title. --- */
  const widget = document.createElement('div');
  widget.className = 'file-browser';

  // Toolbar: breadcrumb, search, upload
  const toolbar = document.createElement('div');
  toolbar.className = 'toolbar';
  breadcrumbEl = document.createElement('div');
  breadcrumbEl.className = 'breadcrumb';
  searchInput = document.createElement('input');
  searchInput.type = 'text';
  searchInput.placeholder = 'Search...';
  const searchBtn = document.createElement('button');
  searchBtn.className = 'btn';
  searchBtn.type = 'button';
  searchBtn.textContent = 'Search';
  const uploadLabel = document.createElement('label');
  uploadLabel.className = 'btn';
  uploadLabel.textContent = 'Upload';
  uploadInput = document.createElement('input');
  uploadInput.type = 'file';
  uploadInput.hidden = true;
  uploadInput.multiple = true;
  uploadLabel.append(uploadInput);
  toolbar.append(breadcrumbEl, searchInput, searchBtn, uploadLabel);

  // Results container + status footer
  resultsEl = document.createElement('div');
  resultsEl.className = 'results';
  statusEl = document.createElement('footer');
  statusEl.className = 'status';

  widget.append(toolbar, resultsEl, statusEl);

  /* --- Embedded host: the primary, chromeless surface. The widget lives here
     while the dialog is closed. --- */
  const embeddedHost = document.createElement('div');
  embeddedHost.className = 'file-browser-host';
  embeddedHost.append(widget);

  /* --- Trigger button --- */
  const trigger = document.createElement('button');
  trigger.className = 'trigger';
  trigger.textContent = 'Browse Files';

  /* --- Native <dialog>: supplies the frame (border/background) and titlebar
     (title + close). Its body is an empty slot the shared widget drops into
     when opened. --- */
  const dialog = document.createElement('dialog');
  dialog.className = 'browser-dialog';

  // Titlebar: centered title + Close (icon) button
  const header = document.createElement('div');
  header.className = 'dialog-header';
  const titleSpan = document.createElement('span');
  titleSpan.className = 'title';
  titleSpan.textContent = 'File Browser';
  const closeBtn = document.createElement('button');
  closeBtn.className = 'close-btn';
  closeBtn.type = 'button';
  // Icon button has no visible text, so expose an accessible name.
  closeBtn.setAttribute('aria-label', 'Close');
  const closeIcon = document.createElement('i');
  closeIcon.className = 'bi bi-x-lg';
  closeBtn.append(closeIcon);
  header.append(titleSpan, closeBtn);

  // Dialog body slot: the widget is moved here on open, back to the host on close.
  const dialogBody = document.createElement('div');
  dialogBody.className = 'dialog-body';

  dialog.append(header, dialogBody);
  root.append(embeddedHost, trigger, dialog);

  /* --- Event wiring --- */
  // Opening the dialog MOVES the shared widget into the dialog body (reusing
  // the same nodes, so module-level refs and any in-flight render stay valid),
  // then shows it. Closing — via the close button, ESC, etc. — fires the
  // dialog's `close` event, which moves the widget back to the embedded host.
  trigger.addEventListener('click', () => {
    dialogBody.append(widget);
    dialog.showModal();
  });
  dialog.addEventListener('close', () => {
    embeddedHost.append(widget);
  });
  closeBtn.addEventListener('click', () => dialog.close());

  searchBtn.addEventListener('click', doSearch);
  searchInput.addEventListener('keydown', (event: KeyboardEvent) => {
    if (event.key === 'Enter') {
      doSearch();
    }
  });

  uploadInput.addEventListener('change', handleUpload);

  /* --- Route subscription + initial render --- */
  // Tear down the previous mount's listener first (if any) so re-mounts never
  // accumulate hashchange listeners on `window`.
  if (unsubscribe !== null) {
    unsubscribe();
    unsubscribe = null;
  }
  unsubscribe = subscribe(render);
  render();
}

/* =========================================================================
 * Toolbar handlers
 * ========================================================================= */

/**
 * Navigate to a search hash for the current input value and browse path.
 *
 * An empty (or whitespace-only) query clears the search instead: it navigates
 * to the browse route for the current path so the server never receives an
 * empty `query`, which it rejects with 400.
 */
function doSearch(): void {
  const path = normalizeRelativePath(getCurrentRoute().path);
  const query = searchInput.value.trim();
  if (query === '') {
    navigate(toBrowseHash(path));
    return;
  }
  navigate(toSearchHash(query, path));
}

/**
 * Upload every selected file to the current path, handle per-file errors, then
 * clear the input, re-render the listing, and surface any failures in the
 * status footer.
 */
async function handleUpload(): Promise<void> {
  const list = uploadInput.files;
  const files = list ? Array.from(list) : [];
  if (files.length === 0) {
    return;
  }
  const path = normalizeRelativePath(getCurrentRoute().path);
  const failed: string[] = [];
  for (const file of files) {
    try {
      await api.upload(path, file);
    } catch {
      failed.push(file.name);
    }
  }
  // Clear the input so selecting the same file again re-fires `change`.
  uploadInput.value = '';
  // Re-render the listing first so normal browse/search status is set.
  await render();
  // Surface failures after the normal render, so the message is not overwritten.
  if (failed.length > 0) {
    const succeeded = files.length - failed.length;
    statusEl.textContent = `Uploaded ${succeeded} file(s); failed: ${failed.join(', ')}`;
  }
}

/* =========================================================================
 * render — route dispatcher
 *
 * Clears the results container synchronously (so a pending/failed fetch never
 * leaves a stale table behind) but does NOT clear the breadcrumb or status
 * here. Clearing those synchronously would remove in-page navigation targets
 * in the middle of a click handler: `navigate()` dispatches `hashchange`
 * synchronously in happy-dom, which would re-enter `render` and wipe the
 * breadcrumb before the click's caller can read the next segment. The
 * breadcrumb/status are instead refreshed by `renderBrowse`/`renderSearch`
 * once data arrives.
 * ========================================================================= */

async function render(): Promise<void> {
  // Claim this render slot. A newer render increments `renderToken` past
  // `myToken`; after each `await` we bail out if superseded so a slower fetch
  // can never overwrite the freshest results, breadcrumb, or status.
  const myToken = ++renderToken;
  const route = getCurrentRoute();
  resultsEl.innerHTML = '';
  try {
    if (route.view === 'browse') {
      const result = await api.browse(normalizeRelativePath(route.path));
      if (myToken !== renderToken) return;
      renderBrowse(result, route);
    } else {
      const result = await api.search(route.query, normalizeRelativePath(route.path));
      if (myToken !== renderToken) return;
      renderSearch(result, route);
    }
  } catch (err) {
    // A superseded render must not even commit its error.
    if (myToken !== renderToken) return;
    // textContent replaces all children, so any stale table is removed too.
    resultsEl.textContent = err instanceof Error
      ? 'Error: ' + err.message
      : 'Error: ' + String(err);
  }
}

/* =========================================================================
 * renderBrowse — table for a BrowseResult
 * ========================================================================= */

export function renderBrowse(result: BrowseResult, route: Route): void {
  void route; // signature per spec; the API result is the source of truth

  // Breadcrumb (clickable cumulative-path segments)
  renderBreadcrumb(result.path);

  // Status footer: "N folders, M files, total S"
  statusEl.textContent =
    result.folderCount + ' folders, ' +
    result.fileCount + ' files, total ' +
    formatBytes(result.totalSize);

  // Results table
  resultsEl.innerHTML = '';
  const table = buildTable(['Name', 'Size', 'Modified', 'Actions']);
  const tbody = table.querySelector('tbody')!;

  if (result.parent !== null) {
    tbody.append(makeParentRow(result.parent));
  }
  for (const entry of result.entries) {
    tbody.append(makeBrowseRow(entry));
  }

  resultsEl.append(table);
}

/* =========================================================================
 * renderSearch — table for a SearchResult
 * ========================================================================= */

export function renderSearch(result: SearchResult, route: Route): void {
  void route;

  // Breadcrumb reflects the search-scope path.
  renderBreadcrumb(result.path);

  // Status footer: 'R results for "q"'
  statusEl.textContent = result.results.length + ' results for "' + result.query + '"';

  // Results table
  resultsEl.innerHTML = '';
  const table = buildTable(['Name', 'Path', 'Size', 'Modified']);
  const tbody = table.querySelector('tbody')!;

  for (const entry of result.results) {
    tbody.append(makeSearchRow(entry));
  }

  resultsEl.append(table);
}

/* =========================================================================
 * DOM-builder helpers
 * ========================================================================= */

/**
 * Build a `<table>` with a `<thead>` (one `<th>` per header label) and an empty
 * `<tbody>`. The caller appends rows to the `<tbody>`.
 */
function buildTable(headers: string[]): HTMLTableElement {
  const table = document.createElement('table');
  table.className = 'results-table';
  const thead = document.createElement('thead');
  const headRow = document.createElement('tr');
  for (const label of headers) {
    const th = document.createElement('th');
    th.textContent = label;
    headRow.append(th);
  }
  thead.append(headRow);
  const tbody = document.createElement('tbody');
  table.append(thead, tbody);
  return table;
}

/**
 * Render clickable breadcrumb segments into `breadcrumbEl`: a leading "Home"
 * link (root) followed by one link per path segment, each navigating to its
 * cumulative path. Separators are plain '/' text spans.
 */
function renderBreadcrumb(path: string): void {
  breadcrumbEl.innerHTML = '';
  const normalized = normalizeRelativePath(path);
  const segments = normalized === '' ? [] : normalized.split('/');

  breadcrumbEl.append(makeNavLink('Home', toBrowseHash('')));

  let cumulative = '';
  for (const segment of segments) {
    cumulative = joinPath(cumulative, segment);
    const separator = document.createElement('span');
    separator.textContent = '/';
    breadcrumbEl.append(separator, makeNavLink(segment, toBrowseHash(cumulative)));
  }
}

/**
 * Build an `<a>` that navigates to `hash` on click. The `href` is set via
 * `setAttribute` (so the raw attribute is preserved exactly — important for
 * download URLs that must not be URL-normalized) and a click handler calls
 * `navigate(hash)` with `preventDefault` so navigation is reliable across DOM
 * implementations. The href also enables middle-click / copy-link support.
 */
function makeNavLink(text: string, hash: string): HTMLAnchorElement {
  const link = document.createElement('a');
  link.setAttribute('href', hash);
  link.textContent = text;
  link.addEventListener('click', (event) => {
    event.preventDefault();
    navigate(hash);
  });
  return link;
}

/** The ".." parent row: a Name cell whose link navigates to the parent path. */
function makeParentRow(parent: string): HTMLTableRowElement {
  const row = document.createElement('tr');
  const nameCell = document.createElement('td');
  nameCell.append(makeNavLink('..', toBrowseHash(parent)));
  const sizeCell = document.createElement('td');
  const modifiedCell = document.createElement('td');
  const actionsCell = document.createElement('td');
  row.append(nameCell, sizeCell, modifiedCell, actionsCell);
  return row;
}

/** One data row in the browse table (a file or folder entry). */
function makeBrowseRow(entry: FileEntry): HTMLTableRowElement {
  const row = document.createElement('tr');

  // Name — directory names are navigation links; file names are plain text.
  const nameCell = document.createElement('td');
  if (entry.isDirectory) {
    nameCell.append(makeNavLink(entry.name, toBrowseHash(entry.path)));
  } else {
    nameCell.textContent = entry.name;
  }

  // Size — em-dash for folders, formatted bytes for files.
  const sizeCell = document.createElement('td');
  sizeCell.textContent = entry.isDirectory ? '—' : formatBytes(entry.size);

  // Modified
  const modifiedCell = document.createElement('td');
  modifiedCell.textContent = formatDate(entry.lastModified);

  // Actions
  const actionsCell = document.createElement('td');
  if (!entry.isDirectory) {
    const download = document.createElement('a');
    download.className = 'btn';
    download.setAttribute('href', api.downloadUrl(entry.path));
    download.setAttribute('download', entry.name);
    download.textContent = 'Download';
    actionsCell.append(download);
  }
  actionsCell.append(makeActionButton('Delete', async () => {
    if (!window.confirm('Delete "' + entry.name + '"?')) {
      return;
    }
    await api.delete(entry.path);
    render();
  }));
  actionsCell.append(makeActionButton('Move', async () => {
    const dest = window.prompt('Move to relative destination path:', entry.path);
    if (dest === null) {
      return;
    }
    await api.move(entry.path, normalizeRelativePath(dest));
    render();
  }));
  actionsCell.append(makeActionButton('Copy', async () => {
    const dest = window.prompt('Copy to relative destination path:', entry.path);
    if (dest === null) {
      return;
    }
    await api.copy(entry.path, normalizeRelativePath(dest));
    render();
  }));

  row.append(nameCell, sizeCell, modifiedCell, actionsCell);
  return row;
}

/**
 * Build a `<button class="btn">` with the given label and click handler.
 *
 * The handler is wrapped so that any synchronous throw or promise rejection
 * surfaces the error via the status footer — consistent with how `render()`
 * already displays fetch errors. On normal resolution no error message is
 * shown.
 */
function makeActionButton(label: string, handler: () => void): HTMLButtonElement {
  const btn = document.createElement('button');
  btn.className = 'btn';
  btn.type = 'button';
  btn.textContent = label;
  btn.addEventListener('click', () => {
    try {
      Promise.resolve(handler()).catch((err: unknown) => {
        statusEl.textContent = 'Error: ' + (err instanceof Error ? err.message : String(err));
      });
    } catch (err) {
      statusEl.textContent = 'Error: ' + (err instanceof Error ? err.message : String(err));
    }
  });
  return btn;
}

/** One data row in the search-results table. */
function makeSearchRow(entry: FileEntry): HTMLTableRowElement {
  const row = document.createElement('tr');

  // Name — directories browse into; files open their download URL.
  const nameCell = document.createElement('td');
  if (entry.isDirectory) {
    nameCell.append(makeNavLink(entry.name, toBrowseHash(entry.path)));
  } else {
    const link = document.createElement('a');
    link.setAttribute('href', api.downloadUrl(entry.path));
    link.textContent = entry.name;
    nameCell.append(link);
  }

  // Path
  const pathCell = document.createElement('td');
  pathCell.textContent = entry.path;

  // Size
  const sizeCell = document.createElement('td');
  sizeCell.textContent = formatBytes(entry.size);

  // Modified
  const modifiedCell = document.createElement('td');
  modifiedCell.textContent = formatDate(entry.lastModified);

  row.append(nameCell, pathCell, sizeCell, modifiedCell);
  return row;
}

