      const { uploadInput, uploadLabel } = setup();
      // `hidden` is the mechanism that actually does the hiding (set in JS as
      // `uploadInput.hidden = true`), so deleting the dead descendant rule
      // `.toolbar label.upload-btn input[type=file] { display: none; }` cannot
      // un-hide the input.
      expect(uploadInput.hidden).toBe(true);
      expect(uploadInput.hasAttribute('hidden')).toBe(true);
      // The input carries no class of its own, and its label ancestor is `btn`
      // not `upload-btn`, so the dead descendant selector never matched it in
      // the first place.
      expect(uploadInput.className).toBe('');
      expect(uploadLabel.classList.contains('upload-btn')).toBe(false);
    });
  });
});

